export async function loadLangSilk(lang: SupportedLanguageSilk): Promise<LocalizationDataSilk> {
	switch (lang) {
		case 'ZH':
			return (await import('./localization-ZH.generated')).default;
		case 'ZH_TW':
			return (await import('./localization-ZH_TW.generated')).default;
		case 'RU':
			return (await import('./localization-RU.generated')).default;
		case 'PT':
			return (await import('./localization-PT.generated')).default;
		case 'KO':
			return (await import('./localization-KO.generated')).default;
		case 'JA':
			return (await import('./localization-JA.generated')).default;
		case 'IT':
			return (await import('./localization-IT.generated')).default;
		case 'FR':
			return (await import('./localization-FR.generated')).default;
		case 'ES':
			return (await import('./localization-ES.generated')).default;
		case 'EN':
			return (await import('./localization-EN.generated')).default;
		case 'DE':
			return (await import('./localization-DE.generated')).default;
		default:
			return assertNever(lang);
	}
}
